import{_ as a,H as t,f as o,i as s}from"./chunks/framework.nN4pLK1d.js";const u=JSON.parse('{"title":"Containers","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/email/concepts/basic/containers.md","filePath":"packages/rcml/email/concepts/basic/containers.md"}'),l={name:"packages/rcml/email/concepts/basic/containers.md"};function n(c,e,r,i,d,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1>Containers</h1><p>Layout containers define the two-dimensional grid of an email. Content elements live inside columns; columns live inside sections.</p><p>Email clients — especially Outlook on Windows — don&#39;t support modern CSS layout. RCML compiles sections and columns to table-based HTML (<code>&lt;table&gt;&lt;tr&gt;&lt;td&gt;</code>), which renders consistently across Outlook, Gmail, Apple Mail, and mobile clients. The section/column abstraction hides this complexity: you describe rows and cells; RCML generates the table markup.</p><h2 id="nesting-hierarchy" tabindex="-1">Nesting hierarchy <a class="header-anchor" href="#nesting-hierarchy" aria-label="Permalink to &quot;Nesting hierarchy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rc-body</span></span>
<span class="line"><span>  └─ rc-wrapper  (optional — shared background or padding around a group of sections)</span></span>
<span class="line"><span>       └─ rc-section  (horizontal row)</span></span>
<span class="line"><span>            ├─ rc-column  (vertical cell)</span></span>
<span class="line"><span>            │    └─ content elements  (rc-text, rc-image, rc-button, …)</span></span>
<span class="line"><span>            └─ rc-group  (optional — keeps its columns side-by-side on mobile)</span></span>
<span class="line"><span>                 └─ rc-column  (vertical cell)</span></span>
<span class="line"><span>                      └─ content elements  (rc-text, rc-image, rc-button, …)</span></span></code></pre></div><p><code>rc-wrapper</code> is optional. Sections can sit directly inside <code>rc-body</code>. <code>rc-group</code> is optional; columns can also sit directly inside <code>rc-section</code>.</p><h2 id="container-elements" tabindex="-1">Container elements <a class="header-anchor" href="#container-elements" aria-label="Permalink to &quot;Container elements&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-section.html"><code>&lt;rc-section&gt;</code></a></td><td>Full-width horizontal row. The primary layout unit. Contains one or more columns (up to 20).</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-column.html"><code>&lt;rc-column&gt;</code></a></td><td>Vertical cell inside a section. All content elements live here.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-wrapper.html"><code>&lt;rc-wrapper&gt;</code></a></td><td>Groups one or more sections under a shared background image or colour.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-group.html"><code>&lt;rc-group&gt;</code></a></td><td>Pass-through container that keeps its columns side-by-side on mobile.</td></tr></tbody></table><p>Use <code>rc-wrapper</code> when multiple adjacent sections should share a visual context — a background colour or image that spans a header image, a headline, and a sub-heading row together. Without a wrapper you&#39;d need to set the same background on each section individually and keep them in sync.</p><p>Use <code>rc-group</code> when a set of columns should stay side-by-side on mobile. By default, mobile email clients stack columns vertically. <code>rc-group</code> prevents that for the columns it contains — useful for icon-label pairs, small product thumbnails, or any layout that looks broken when stacked.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/elements.html">Elements</a> — the content elements that go inside columns</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-section.html"><code>&lt;rc-section&gt;</code> reference</a></li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-column.html"><code>&lt;rc-column&gt;</code> reference</a></li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-wrapper.html"><code>&lt;rc-wrapper&gt;</code> reference</a></li><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/layout/rc-group.html"><code>&lt;rc-group&gt;</code> reference</a></li></ul>`,12)])])}const h=a(l,[["render",n]]);export{u as __pageData,h as default};
